using Microsoft.AspNetCore.Mvc; using VoiceAgent.Application.Interfaces; using VoiceAgent.Common.Responses;
namespace VoiceAgent.Api.Controllers; [ApiController][Route("api/[controller]")] public class CallsController(ICallQueryService service):ControllerBase{ [HttpGet] public ActionResult<ApiResponse<object>> Get()=>Ok(new ApiResponse<object>{Success=true,Data=Array.Empty<object>()}); [HttpGet("{id:guid}")] public async Task<ActionResult<ApiResponse<object?>>> GetById(Guid id,CancellationToken ct)=>Ok(new ApiResponse<object?>{Success=true,Data=await service.GetSessionAsync(id,ct)}); [HttpGet("{id:guid}/turns")] public ActionResult<ApiResponse<object>> Turns(Guid id)=>Ok(new ApiResponse<object>{Success=true,Data=Array.Empty<object>()}); [HttpGet("{id:guid}/events")] public ActionResult<ApiResponse<object>> Events(Guid id)=>Ok(new ApiResponse<object>{Success=true,Data=Array.Empty<object>()}); [HttpGet("{id:guid}/tool-logs")] public ActionResult<ApiResponse<object>> ToolLogs(Guid id)=>Ok(new ApiResponse<object>{Success=true,Data=Array.Empty<object>()}); }
